import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.BufferedReader;
import java.io.IOException;
import java.nio.charset.Charset;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserParsePathTest {

    private Path mockPath;
    private Charset charset;
    private CSVFormat format;

    @BeforeEach
    void setUp() throws IOException {
        mockPath = mock(Path.class);
        charset = Charset.defaultCharset();
        format = mock(CSVFormat.class);

        // Mock Files.newBufferedReader(Path, Charset) to return a BufferedReader
        // Since Files.newBufferedReader is static, use Mockito's mockStatic
        // But Mockito 3 requires inline mock maker for static mocking
        // Instead, we create a temporary file and use real Files.newBufferedReader

        // However, to avoid IO, we can use a spy on CSVParser and override parse(Reader, CSVFormat)
        // But since parse(Path, Charset, CSVFormat) calls Files.newBufferedReader, we need to mock that static method.

        // So, we will use Mockito's mockStatic to mock Files.newBufferedReader
    }

    @Test
    void parse_nullPath_throwsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse((Path) null, charset, format));
        assertEquals("path", ex.getMessage());
    }

    @Test
    void parse_nullFormat_throwsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(mockPath, charset, null));
        assertEquals("format", ex.getMessage());
    }

    @Test
    void parse_returnsNonNullParser() throws IOException {
        try (var mocked = mockStatic(Files.class)) {
            BufferedReader mockReader = mock(BufferedReader.class);
            mocked.when(() -> Files.newBufferedReader(mockPath, charset)).thenReturn(mockReader);

            // Also mock CSVParser.parse(Reader, CSVFormat) to return a dummy CSVParser
            try (var csvParserMocked = mockStatic(CSVParser.class, invocation -> {
                if ("parse".equals(invocation.getMethod().getName())
                        && invocation.getArgumentCount() == 2
                        && invocation.getArgument(0) instanceof BufferedReader
                        && invocation.getArgument(1) instanceof CSVFormat) {
                    return new CSVParser(mockReader, format);
                }
                return invocation.callRealMethod();
            })) {
                CSVParser actualParser = CSVParser.parse(mockPath, charset, format);
                assertNotNull(actualParser);
            }
        }
    }
}
